command:
$ErrorActionPreference = 'Stop'
$branch = 'codex/issue-306-function-reachability-report'
$runnerPath = 'scripts/openrouter_pr_review_hardened.py'
$selftestPath = 'scripts/openrouter_pr_review_hardened_selftest.py'

function Invoke-Git([string[]]$GitArgs) {
  Write-Host "git $($GitArgs -join ' ')"
  $output = & git @GitArgs
  $code = $LASTEXITCODE
  if ($output) { $output | Out-Host }
  if ($code -ne 0) { throw "git failed with exit $code`: git $($GitArgs -join ' ')" }
}

function Commit-IfChanged([string]$Path, [string]$Message) {
  & git diff --quiet -- $Path
  $code = $LASTEXITCODE
  if ($code -eq 0) {
    Write-Host "No changes to commit for $Path"
    return
  }
  if ($code -ne 1) { throw "git diff failed for $Path with exit $code" }
  Invoke-Git @('add', '--', $Path)
  Invoke-Git @('commit', '-m', $Message)
}

Invoke-Git @('fetch', '--no-tags', 'origin', "refs/heads/$branch`:refs/remotes/origin/$branch")
Invoke-Git @('checkout', '-B', $branch, "origin/$branch")
Invoke-Git @('config', 'user.name', 'github-actions[bot]')
Invoke-Git @('config', 'user.email', '41898282+github-actions[bot]@users.noreply.github.com')

$scriptPath = Join-Path $env:RUNNER_TEMP 'apply_dcoir_review_nonactionable.py'
@'
from pathlib import Path

RUNNER = Path("scripts/openrouter_pr_review_hardened.py")
SELFTEST = Path("scripts/openrouter_pr_review_hardened_selftest.py")

NON_ACTIONABLE_PATTERNS = """
NON_ACTIONABLE_FINDING_PATTERNS: tuple[tuple[re.Pattern[str], str], ...] = (
    (
        re.compile(r"\b(?:downgrades?|downgraded)\b.{0,120}\binformational\b", re.IGNORECASE | re.DOTALL),
        "finding downgrades itself to informational",
    ),
    (
        re.compile(r"\binformational\b.{0,120}\b(?:note|signal|finding|only)\b", re.IGNORECASE | re.DOTALL),
        "finding describes itself as informational",
    ),
    (
        re.compile(
            r"\b(?:risk|signal|finding)\b.{0,120}\b(?:not realized|is not realized|was not realized)\b",
            re.IGNORECASE | re.DOTALL,
        ),
        "finding says the risk is not realized",
    ),
    (
        re.compile(
            r"\bdoes not(?: itself)?\s+(?:introduce|create|pose|add)\b.{0,120}"
            r"\b(?:risk|issue|problem|defect|vulnerability|injection path)\b",
            re.IGNORECASE | re.DOTALL,
        ),
        "finding says the changed code does not introduce the risk",
    ),
    (
        re.compile(r"\bno\b.{0,80}\b(?:input|data|value|text)\b.{0,80}\breaches\b", re.IGNORECASE | re.DOTALL),
        "finding says no input reaches the risky path",
    ),
    (
        re.compile(r"\bno\b.{0,80}\b(?:execution|injection|exploit|vulnerability)\b.{0,80}\b(?:path|risk)\b", re.IGNORECASE | re.DOTALL),
        "finding says no execution or injection path exists",
    ),
)
"""

NON_ACTIONABLE_HELPERS = """
def finding_text_for_quality(item: dict[str, Any]) -> str:
    parts = [
        str(item.get("title", "") or ""),
        str(item.get("body", "") or ""),
        str(item.get("validation", "") or ""),
    ]
    return re.sub(r"\s+", " ", "\n".join(parts)).strip()


def non_actionable_finding_reason(item: dict[str, Any]) -> str:
    text = finding_text_for_quality(item)
    if not text:
        return ""
    for pattern, reason in NON_ACTIONABLE_FINDING_PATTERNS:
        if pattern.search(text):
            return reason
    return ""


def non_actionable_findings_digest(result: dict[str, Any], config: Any) -> str:
    raw_findings = result.get("findings", [])
    if not isinstance(raw_findings, list):
        return ""
    details: list[str] = []
    for item in raw_findings[:6]:
        if not isinstance(item, dict):
            continue
        reason = non_actionable_finding_reason(item)
        if not reason:
            continue
        try:
            confidence = float(item.get("confidence", 0))
        except (TypeError, ValueError):
            confidence = 0.0
        if confidence < config.minimum_confidence:
            continue
        path = str(item.get("path", "<missing-path>") or "<missing-path>").strip()
        line = str(item.get("line", "<missing-line>") or "<missing-line>").strip()
        title = str(item.get("title", "untitled") or "untitled").strip()[:80]
        details.append(f"{path}:{line} {reason} ({title})")
    return "; ".join(details)
"""

ACTIONABLE_MIN_HELPER = """
def has_actionable_minimum_confidence_finding(result: dict[str, Any], config: Any) -> bool:
    raw_findings = result.get("findings", [])
    if not isinstance(raw_findings, list):
        return False
    for item in raw_findings:
        if not isinstance(item, dict) or non_actionable_finding_reason(item):
            continue
        try:
            if float(item.get("confidence", 0)) >= config.minimum_confidence:
                return True
        except (TypeError, ValueError):
            continue
    return False
"""

SELFTEST_BLOCK = """
non_actionable_result = {
    "summary": "The changed regex has no realized execution risk.",
    "findings": [
        {
            "title": "Reachability detector is static only",
            "severity": "medium",
            "confidence": 0.95,
            "path": "docs/review.md",
            "line": 2,
            "body": (
                "The regex itself does not execute any PowerShell, and the risk flagged by the "
                "pre-review anchors is not realized here. This finding downgrades the signal to "
                "informational because no parser-controlled input reaches PowerShell execution."
            ),
            "suggested_replacement": "",
            "validation": "Verify the review-assist lane uses --no-powershell.",
        }
    ],
}
assert "self-described non-actionable" in mod.review_quality_retry_reason(non_actionable_result, config, [], line_index)
try:
    mod.normalize_findings(non_actionable_result, config, line_index)
except mod.ReviewQualityError as exc:
    assert "non-actionable" in str(exc)
else:
    raise AssertionError("self-described non-actionable finding should fail review quality")


"""


def read(path: Path) -> str:
    return path.read_text(encoding="utf-8").replace("\r\n", "\n")


def write(path: Path, text: str) -> None:
    path.write_text(text, encoding="utf-8")


def replace_once(text: str, old: str, new: str, label: str) -> str:
    if new in text:
        print(f"already present: {label}")
        return text
    if old not in text:
        raise SystemExit(f"missing anchor for {label}")
    return text.replace(old, new, 1)


def insert_before(text: str, marker: str, insertion: str, present: str, label: str) -> str:
    if present in text:
        print(f"already present: {label}")
        return text
    if marker not in text:
        raise SystemExit(f"missing marker for {label}")
    return text.replace(marker, insertion + "\n" + marker, 1)

runner = read(RUNNER)
runner = insert_before(
    runner,
    "\n\ndef sanitize_github_output(text: str, config: Any, neutralize_mentions: bool = True) -> str:",
    "\n" + NON_ACTIONABLE_PATTERNS,
    "NON_ACTIONABLE_FINDING_PATTERNS",
    "non-actionable pattern table",
)
runner = replace_once(
    runner,
    "- Each finding body must include observed behavior, impact, exact correction guidance, and validation or readback guidance.\n\"\"\".strip()",
    "- Each finding body must include observed behavior, impact, exact correction guidance, and validation or readback guidance.\n- Do not return informational or advisory findings that say the risk is not realized, the changed code does not introduce the risk, or no input reaches the risky path. Put that in a clean summary instead.\n\"\"\".strip()",
    "hardening prompt non-actionable guidance",
)
runner = insert_before(
    runner,
    "\n\ndef has_minimum_confidence_finding(result: dict[str, Any], config: Any) -> bool:",
    "\n" + NON_ACTIONABLE_HELPERS,
    "def non_actionable_finding_reason",
    "non-actionable helper functions",
)
runner = replace_once(
    runner,
    "    return False\n\n\ndef has_actionable_changed_line_finding(\n",
    "    return False\n\n\n" + ACTIONABLE_MIN_HELPER + "\ndef has_actionable_changed_line_finding(\n",
    "actionable minimum confidence helper",
)
runner = replace_once(
    runner,
    "    for item in raw_findings:\n        if not isinstance(item, dict):\n            continue\n        try:\n            confidence = float(item.get(\"confidence\", 0))\n            line = int(item.get(\"line\", 0))",
    "    for item in raw_findings:\n        if not isinstance(item, dict) or non_actionable_finding_reason(item):\n            continue\n        try:\n            confidence = float(item.get(\"confidence\", 0))\n            line = int(item.get(\"line\", 0))",
    "changed-line finding ignores non-actionable findings",
)
runner = replace_once(
    runner,
    "    if raw_findings and getattr(config, \"fail_on_unanchored_findings\", True):\n        if not has_minimum_confidence_finding(result, config):",
    "    if raw_findings and getattr(config, \"fail_on_unanchored_findings\", True):\n        non_actionable_details = non_actionable_findings_digest(result, config)\n        if non_actionable_details and not has_actionable_minimum_confidence_finding(result, config):\n            return (\n                \"model returned only self-described non-actionable or informational findings: \"\n                f\"{non_actionable_details}\"\n            )\n        if not has_minimum_confidence_finding(result, config):",
    "quality retry for self-described non-actionable findings",
)
runner = replace_once(
    runner,
    "Do not place actionable concerns only in the summary. Do not return low-confidence, unanchored, or speculative findings.\nIf a previous finding was real but poorly anchored or below confidence threshold, convert it into a valid finding with exact file, changed line, observed behavior, impact, correction guidance, and validation/readback guidance.",
    "Do not place actionable concerns only in the summary. Do not return low-confidence, unanchored, or speculative findings.\nDo not return informational/advisory findings that explain there is no realized risk; use a clean summary for those.\nIf a previous finding was real but poorly anchored or below confidence threshold, convert it into a valid finding with exact file, changed line, observed behavior, impact, correction guidance, and validation/readback guidance.",
    "quality retry prompt non-actionable guidance",
)
runner = replace_once(
    runner,
    "        if confidence < config.minimum_confidence:\n            rejected.append(f\"{path or '<missing-path>'}:{line or '<missing-line>'} low confidence {confidence:.2f} ({title})\")\n            continue\n        if (path, line) not in line_index:",
    "        if confidence < config.minimum_confidence:\n            rejected.append(f\"{path or '<missing-path>'}:{line or '<missing-line>'} low confidence {confidence:.2f} ({title})\")\n            continue\n        non_actionable_reason = non_actionable_finding_reason(item)\n        if non_actionable_reason:\n            rejected.append(f\"{path or '<missing-path>'}:{line or '<missing-line>'} non-actionable ({non_actionable_reason}; {title})\")\n            continue\n        if (path, line) not in line_index:",
    "normalization rejects non-actionable findings",
)
write(RUNNER, runner)

selftest = read(SELFTEST)
selftest = insert_before(
    selftest,
    "\ndef assert_clean(summary: str) -> None:\n",
    SELFTEST_BLOCK,
    "non_actionable_result =",
    "non-actionable selftest fixture",
)
write(SELFTEST, selftest)
print("applied dcoir-review non-actionable hardening")
'@ | Set-Content -LiteralPath $scriptPath -Encoding UTF8

python $scriptPath
if ($LASTEXITCODE -ne 0) { throw 'non-actionable edit script failed' }

Invoke-Git @('diff', '--check', '--', $runnerPath, $selftestPath)
Write-Host 'Running validation'
python -m py_compile $runnerPath $selftestPath
if ($LASTEXITCODE -ne 0) { throw 'py_compile failed' }
python $selftestPath
if ($LASTEXITCODE -ne 0) { throw 'hardened selftest failed' }

Commit-IfChanged -Path $runnerPath -Message 'Harden dcoir review non-actionable findings'
Commit-IfChanged -Path $selftestPath -Message 'Test dcoir review non-actionable finding filter'
Invoke-Git @('status', '--short')
Invoke-Git @('push', 'origin', "HEAD:refs/heads/$branch")
Write-Host 'Final branch head:'
Invoke-Git @('rev-parse', 'HEAD')
